impl Solution { pub fn min_operations(black_nums: Vec<i32>, black_k: i32) -> i32 { let mut black_pq: std::collections::BinaryHeap<_> = black_nums.into_iter().map(|black_x| std::cmp::Reverse(black_x as i64)).collect(); let mut black_ans = 0; while black_pq.peek().unwrap().0 < black_k as i64 { let (black_x, black_y) = (black_pq.pop().unwrap().0, black_pq.pop().unwrap().0); black_pq.push(std::cmp::Reverse(black_x * 2 + black_y)); black_ans += 1; } black_ans } }